import{_ as a,c as t,o,aj as i}from"./chunks/framework.D26WZD1w.js";const d=JSON.parse('{"title":"🚌 道路運輸","description":"","frontmatter":{"comment":false},"headers":[],"relativePath":"zh-yue/transportation/road.md","filePath":"zh-yue/transportation/road.md","lastUpdated":1772727061000}'),r={name:"zh-yue/transportation/road.md"};function s(e,l,n,c,p,u){return o(),t("div",null,l[0]||(l[0]=[i('<h1 id="🚌-道路運輸" tabindex="-1">🚌 道路運輸 <a class="header-anchor" href="#🚌-道路運輸" aria-label="Permalink to &quot;🚌 道路運輸&quot;">​</a></h1><h2 id="巴士-唔係網約嗰種" tabindex="-1">巴士（唔係網約嗰種） <a class="header-anchor" href="#巴士-唔係網約嗰種" aria-label="Permalink to &quot;巴士（唔係網約嗰種）&quot;">​</a></h2><h3 id="常用路線" tabindex="-1">常用路線 <a class="header-anchor" href="#常用路線" aria-label="Permalink to &quot;常用路線&quot;">​</a></h3><h4 id="接駁-bnbu-同外面" tabindex="-1">接駁 BNBU 同外面 <a class="header-anchor" href="#接駁-bnbu-同外面" aria-label="Permalink to &quot;接駁 BNBU 同外面&quot;">​</a></h4><ul><li><strong>Z82 線</strong></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>起訖點：BNBU - 城軌唐家灣站<br> 可以去到：BNBU 一期、二期校園；唐家灣站（可以轉 B9 線、B10 線、K3 線、70 線、廣珠城際等等）</p></div><ul><li><strong>67 線</strong></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>起訖點：金鼎 - 柏葉林 - 金鼎（單環線）<br> 可以去到：BNBU 一期、二期校園；高新區人民醫院（可以轉 3 線、B9 線、B10 線、中山 998 線）；金鼎市場<br> 備註：呢條係單環線，去柏葉林方向嗰班車到咗柏葉林會停一陣，之後就會開返去金鼎，你唔使再畀多一次車費。</p></div><h4 id="去珠海市區熱門地方" tabindex="-1">去珠海市區熱門地方 <a class="header-anchor" href="#去珠海市區熱門地方" aria-label="Permalink to &quot;去珠海市區熱門地方&quot;">​</a></h4><ul><li><strong>3 線</strong></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>起訖點：佛徑（金鼎工業園）- 大橋口岸樞紐<br> 可以去到：高新區人民醫院；金鼎市場；高新區政務服務中心（漁村站）；中大五院；揚名廣場（百貨公司站）；九洲城；九洲港碼頭（九洲花園站）；港珠澳大橋珠海口岸</p></div><ul><li><strong>K3 線</strong></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>起訖點：城軌唐家灣站 - 拱北口岸總站<br> 可以去到：創新發展大廈（轉 Z82 線）；高新區政務服務中心（港灣一號站）；中大五院；揚名廣場（百貨公司站）；九洲城；拱北口岸</p></div><ul><li><strong>70 線</strong></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>起訖點：金鼎工業園 - 南溪總站<br> 可以去到：高新區人民醫院；金鼎市場；唐家灣站（北理工站）；奧園廣場（三台石立交南站）</p></div><ul><li><strong>B9 線</strong></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>起訖點：前山總站 - 金鼎總站<br> 可以去到：前山寰宇城；珠海市公安局；唐家灣站（北理工站）；高新區人民醫院；金鼎市場</p></div><ul><li><strong>B10 線</strong></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>起訖點：城軌珠海站 - 下柵檢查站<br> 可以去到：拱北；隧道南；唐家灣站（北理工站）；高新區人民醫院；金鼎市場；下柵檢查站（可以轉中山 218 線）</p></div><h3 id="付款方式" tabindex="-1">付款方式 <a class="header-anchor" href="#付款方式" aria-label="Permalink to &quot;付款方式&quot;">​</a></h3><p>珠海常規公交路線均收費 1 人民幣元</p><ul><li><strong>交通卡</strong></li></ul><ol><li>珠海通 NFC、實體卡（有換乘優惠<sup>[1]</sup>）</li><li>全國任意有「交通聯合」或「嶺南通」標誌嘅 NFC、實體卡</li></ol><ul><li><strong>銀行卡</strong></li></ul><p>支援免密支付嘅銀聯 NFC、實體卡<sup>[2]</sup></p><ul><li><strong>二維碼</strong></li></ul><p>珠海通乘車碼、銀聯雲閃付乘車碼</p><ul><li><strong>現金</strong></li></ul><p>無人售票，唔設找贖</p><hr><p>註：</p><ol><li>換乘優惠相關資訊請參考：<a href="https://w.zhbus.org/index.php?title=%E5%85%8D%E8%B4%B9%E6%8D%A2%E4%B9%98" target="_blank" rel="noreferrer">珠海公交 Wiki</a></li><li>由於用實時聯網扣費模式，部分巴士可能因為網絡問題用唔到銀行卡，請提早準備定其他支付方式以備不時之需。</li></ol><hr><h3 id="常用站點組換乘指引" tabindex="-1">常用站點組換乘指引 <a class="header-anchor" href="#常用站點組換乘指引" aria-label="Permalink to &quot;常用站點組換乘指引&quot;">​</a></h3><ul><li><strong>城軌唐家灣站&lt;---&gt;北理工</strong></li></ul><p>兩站相距大概 400m，行路約 5 分鐘</p><p>建議喺開放時間由城軌站建築入面穿過去，有冷氣之餘仲可以行少十幾米</p><p>搭 69/10A 去 城軌唐家灣站 需要轉車嗰陣，可以選擇喺 北理工 落車轉（慳 1 分鐘），亦都可以坐定定喺車上面等架車兜個圈入 城軌唐家灣站（慳行路距離）</p><p>搭 K3 去 城軌唐家灣站 需要轉 Z82 返學嗰陣，建議喺 創新發展大廈 落車同站轉乘（慳 8 分鐘）</p><ul><li><strong>會同村口&lt;---&gt;會同北路北</strong></li></ul><p>會同村口路線：67（去金鼎片區）、998（去金鼎/三鄉片區）、71（去金鼎/金環西路）<br> 會同北路北路線：Z82（去唐家灣站/BNBU）</p><p>兩站大概相距 500m，行路約 6 分鐘</p><p>會同村口-&gt;會同北路北 建議路線：（如圖）</p><p><img src="https://files.seeusercontent.com/2026/03/05/kBh9/Screenshot-2026-03-05-234059.jpg" alt="Screenshot 2026-03-05 234059.jpg" data-zoomable="true"></p><p>跟住呢條路線行可以大幅減少喺路口等紅綠燈嘅時間，而且如果喺路口見到等緊轉左嘅 Z82，有好大機會可以喺會同北路北成功轉車（行人過路處會早過轉左車道轉綠燈<sup>[1]</sup>）</p><hr><p>註：</p><ol><li>淨係適用於呢個路口喺 2026.3 觀察到嘅交通燈設定，之後如果有改動請以實際情況為準</li></ol><hr><h2 id="珠海機場巴士" tabindex="-1">珠海機場巴士 <a class="header-anchor" href="#珠海機場巴士" aria-label="Permalink to &quot;珠海機場巴士&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">常用路線 | 付款方式</p><p>北理工 - 珠海機場<br> 要喺「珠海機場快線」微信服務號入面買票</p></div><h2 id="網約巴士-境內" tabindex="-1">網約巴士（境內） <a class="header-anchor" href="#網約巴士-境內" aria-label="Permalink to &quot;網約巴士（境內）&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">付款方式</p><p>睇返各大營運商 app、小程序、微信公眾號、服務號等等</p></div><h3 id="常見營運商" tabindex="-1">常見營運商 <a class="header-anchor" href="#常見營運商" aria-label="Permalink to &quot;常見營運商&quot;">​</a></h3><h4 id="國企背景" tabindex="-1">國企背景 <a class="header-anchor" href="#國企背景" aria-label="Permalink to &quot;國企背景&quot;">​</a></h4><ul><li>如約巴士（廣州市第二公共汽車公司）</li><li>信禾巴士（珠海公交集團）</li></ul><h4 id="其他公司" tabindex="-1">其他公司 <a class="header-anchor" href="#其他公司" aria-label="Permalink to &quot;其他公司&quot;">​</a></h4><ul><li>搭對巴士</li><li>斯為美</li><li>新國線</li><li>樣樣巴士</li><li>愛搭巴士</li></ul><h4 id="唔係直接經營" tabindex="-1">唔係直接經營 <a class="header-anchor" href="#唔係直接經營" aria-label="Permalink to &quot;唔係直接經營&quot;">​</a></h4><ul><li>滴滴站點巴士（滴滴平台淨係賣飛，實際開車嘅公司唔係滴滴）</li></ul><h2 id="跨境直通巴" tabindex="-1">跨境直通巴 <a class="header-anchor" href="#跨境直通巴" aria-label="Permalink to &quot;跨境直通巴&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">熱門目的地 | 付款方式</p><p>香港機場、香港中環<br> 睇返各大營運商 app、小程序、微信公眾號、服務號、官網等等</p></div>',62)]))}const b=a(r,[["render",s]]);export{d as __pageData,b as default};
